const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: '*',
    methods: ['GET', 'POST']
  }
});

app.use(express.json());

const PORT = process.env.PORT || 3000;
const SESSION_TTL_MS = 1000 * 60 * 60 * 24;
const sessions = new Map();
const players = new Map();
const leaderboard = new Map();

function now() {
  return Date.now();
}

function createSession(username) {
  const token = crypto.randomBytes(32).toString('hex');
  const session = {
    token,
    username,
    createdAt: now(),
    expiresAt: now() + SESSION_TTL_MS
  };
  sessions.set(token, session);
  return session;
}

function getSession(token) {
  const session = sessions.get(token);
  if (!session) return null;
  if (session.expiresAt < now()) {
    sessions.delete(token);
    return null;
  }
  return session;
}

function refreshSession(token) {
  const session = getSession(token);
  if (!session) return null;
  session.expiresAt = now() + SESSION_TTL_MS;
  sessions.set(token, session);
  return session;
}

function sanitizeUsername(username) {
  if (typeof username !== 'string') return null;
  const trimmed = username.trim();
  if (!trimmed || trimmed.length < 3 || trimmed.length > 20) return null;
  if (!/^[a-zA-Z0-9_]+$/.test(trimmed)) return null;
  return trimmed;
}

function getLeaderboard() {
  return Array.from(leaderboard.entries())
    .map(([username, score]) => ({ username, score }))
    .sort((a, b) => b.score - a.score)
    .slice(0, 100);
}

app.post('/auth/login', (req, res) => {
  const username = sanitizeUsername(req.body?.username);
  if (!username) {
    return res.status(400).json({ error: 'Invalid username' });
  }

  const session = createSession(username);

  if (!leaderboard.has(username)) {
    leaderboard.set(username, 0);
  }

  return res.json({
    token: session.token,
    username: session.username,
    expiresAt: session.expiresAt
  });
});

app.post('/auth/restore', (req, res) => {
  const token = req.body?.token;
  if (typeof token !== 'string') {
    return res.status(400).json({ error: 'Invalid token' });
  }

  const session = refreshSession(token);
  if (!session) {
    return res.status(401).json({ error: 'Session expired or invalid' });
  }

  return res.json({
    token: session.token,
    username: session.username,
    expiresAt: session.expiresAt
  });
});

app.get('/leaderboard', (req, res) => {
  res.json({ leaderboard: getLeaderboard() });
});

io.use((socket, next) => {
  const token =
    socket.handshake.auth?.token ||
    socket.handshake.headers['x-session-token'] ||
    socket.handshake.query?.token;

  if (typeof token !== 'string') {
    return next(new Error('Unauthorized'));
  }

  const session = refreshSession(token);
  if (!session) {
    return next(new Error('Unauthorized'));
  }

  socket.data.session = session;
  next();
});

io.on('connection', (socket) => {
  const { username, token } = socket.data.session;

  players.set(socket.id, {
    socketId: socket.id,
    username,
    token,
    connectedAt: now(),
    lastSeenAt: now(),
    score: leaderboard.get(username) || 0
  });

  socket.emit('session', {
    username,
    token,
    expiresAt: sessions.get(token)?.expiresAt
  });

  socket.emit('leaderboard:update', getLeaderboard());

  socket.broadcast.emit('player:joined', {
    socketId: socket.id,
    username
  });

  socket.on('player:move', (payload = {}) => {
    const player = players.get(socket.id);
    if (!player) return;

    player.lastSeenAt = now();

    const move = {
      x: Number(payload.x) || 0,
      y: Number(payload.y) || 0,
      direction: typeof payload.direction === 'string' ? payload.direction : 'none',
      timestamp: Number(payload.timestamp) || now()
    };

    io.emit('player:moved', {
      socketId: socket.id,
      username: player.username,
      move
    });
  });

  socket.on('score:update', (payload = {}) => {
    const player = players.get(socket.id);
    if (!player) return;

    player.lastSeenAt = now();

    const score = Number(payload.score);
    if (!Number.isFinite(score)) {
      socket.emit('error:score', { error: 'Invalid score' });
      return;
    }

    player.score = score;
    leaderboard.set(player.username, score);

    io.emit('score:updated', {
      socketId: socket.id,
      username: player.username,
      score
    });

    io.emit('leaderboard:update', getLeaderboard());
  });

  socket.on('heartbeat', () => {
    const player = players.get(socket.id);
    if (!player) return;
    player.lastSeenAt = now();
    refreshSession(token);
    socket.emit('heartbeat:ack', { time: now() });
  });

  socket.on('disconnect', () => {
    const player = players.get(socket.id);
    if (player) {
      players.delete(socket.id);
      socket.broadcast.emit('player:left', {
        socketId: socket.id,
        username: player.username
      });
    }
  });
});

setInterval(() => {
  const current = now();
  for (const [token, session] of sessions.entries()) {
    if (session.expiresAt < current) {
      sessions.delete(token);
    }
  }
}, 60 * 1000);

server.listen(PORT, () => {
  console.log(`Game server listening on port ${PORT}`);
});